import{_ as a,o as l,c as e,ag as r}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"沃伦·巴菲特（Warren E. Buffett）","description":"","frontmatter":{},"headers":[],"relativePath":"04_people/沃伦·巴菲特.md","filePath":"04_people/沃伦·巴菲特.md"}'),i={name:"04_people/沃伦·巴菲特.md"};function d(o,t,h,n,u,s){return l(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="沃伦·巴菲特-warren-e-buffett" tabindex="-1">沃伦·巴菲特（Warren E. Buffett） <a class="header-anchor" href="#沃伦·巴菲特-warren-e-buffett" aria-label="Permalink to &quot;沃伦·巴菲特（Warren E. Buffett）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>全名</td><td>Warren Edward Buffett</td></tr><tr><td>出生</td><td>1930年8月30日</td></tr><tr><td>公司</td><td><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a></td></tr><tr><td>职位</td><td>董事长兼CEO</td></tr><tr><td>任期</td><td>1965年至今</td></tr></tbody></table><h2 id="职业生涯" tabindex="-1">职业生涯 <a class="header-anchor" href="#职业生涯" aria-label="Permalink to &quot;职业生涯&quot;">​</a></h2><h3 id="早期" tabindex="-1">早期 <a class="header-anchor" href="#早期" aria-label="Permalink to &quot;早期&quot;">​</a></h3><ul><li>1950年：哥伦比亚大学商学院（师从本·格雷厄姆）</li><li>1956年：创办巴菲特合伙公司</li><li>1965年：收购伯克希尔纺织公司控制权</li></ul><h3 id="伯克希尔转型" tabindex="-1">伯克希尔转型 <a class="header-anchor" href="#伯克希尔转型" aria-label="Permalink to &quot;伯克希尔转型&quot;">​</a></h3><ul><li>1967年：收购国家赔偿公司（保险）</li><li>1972年：通过蓝筹印花收购喜诗糖果</li><li>1983年：蓝筹印花与伯克希尔合并</li><li>1985年：关闭纺织业务（原主业）</li><li>1985年：投资首都城市/ABC</li><li>1987年：投资所罗门兄弟</li></ul><h2 id="投资哲学演变" tabindex="-1">投资哲学演变 <a class="header-anchor" href="#投资哲学演变" aria-label="Permalink to &quot;投资哲学演变&quot;">​</a></h2><h3 id="早期-格雷厄姆式" tabindex="-1">早期：格雷厄姆式 <a class="header-anchor" href="#早期-格雷厄姆式" aria-label="Permalink to &quot;早期：格雷厄姆式&quot;">​</a></h3><ul><li>&quot;烟蒂&quot;投资法</li><li>买便宜货，不论质量</li><li>分散持仓</li></ul><h3 id="中期-芒格影响" tabindex="-1">中期：芒格影响 <a class="header-anchor" href="#中期-芒格影响" aria-label="Permalink to &quot;中期：芒格影响&quot;">​</a></h3><ul><li>&quot;合理价买好企业&quot;（1972年喜诗糖果）</li><li>质量优先于价格</li><li>集中持仓</li></ul><h3 id="成熟期-特许权价值" tabindex="-1">成熟期：特许权价值 <a class="header-anchor" href="#成熟期-特许权价值" aria-label="Permalink to &quot;成熟期：特许权价值&quot;">​</a></h3><ul><li>经济商誉理论（1983年附录）</li><li>买入优秀企业永久持有</li><li>能力圈原则</li></ul><h2 id="管理风格" tabindex="-1">管理风格 <a class="header-anchor" href="#管理风格" aria-label="Permalink to &quot;管理风格&quot;">​</a></h2><h3 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><ol><li><strong>资本配置集权</strong>：所有重大投资决策由巴菲特做出</li><li><strong>运营分权</strong>：子公司经理人完全自主</li><li><strong>信任管理</strong>：几乎不干预子公司运营</li><li><strong>长期导向</strong>：不关心季度业绩</li></ol><h3 id="管理理念" tabindex="-1">管理理念 <a class="header-anchor" href="#管理理念" aria-label="Permalink to &quot;管理理念&quot;">​</a></h3><ul><li>&quot;我们买的是企业，不是股票&quot;</li><li>&quot;宁愿以X价格买好企业10%，不愿以2X价格买100%&quot;</li><li>&quot;资本配置是CEO唯一不可委托的工作&quot;</li></ul><h2 id="经典论述" tabindex="-1">经典论述 <a class="header-anchor" href="#经典论述" aria-label="Permalink to &quot;经典论述&quot;">​</a></h2><h3 id="股东信中的核心观点" tabindex="-1">股东信中的核心观点 <a class="header-anchor" href="#股东信中的核心观点" aria-label="Permalink to &quot;股东信中的核心观点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>主题</th><th>金句</th></tr></thead><tbody><tr><td>1978</td><td>合并会计</td><td>&quot;完全合并遮蔽经济现实&quot;</td></tr><tr><td>1980</td><td>通胀税</td><td>&quot;通胀是最可怕的税&quot;</td></tr><tr><td>1981</td><td>股权增值</td><td>&quot;被动16% &gt; 主动14%&quot;</td></tr><tr><td>1983</td><td>商誉经济学</td><td>&quot;经济商誉vs会计商誉&quot;</td></tr><tr><td>1984</td><td>分红政策</td><td>&quot;留存盈利何时创造价值&quot;</td></tr><tr><td>1985</td><td>纺织退出</td><td>&quot;研究失败的价值&quot;</td></tr></tbody></table><h2 id="个人特点" tabindex="-1">个人特点 <a class="header-anchor" href="#个人特点" aria-label="Permalink to &quot;个人特点&quot;">​</a></h2><h3 id="生活习惯" tabindex="-1">生活习惯 <a class="header-anchor" href="#生活习惯" aria-label="Permalink to &quot;生活习惯&quot;">​</a></h3><ul><li>住所：1958年花3.15万美元买的房子，至今居住</li><li>饮食：可乐、汉堡、牛排</li><li>作息：每天阅读5-6小时</li></ul><h3 id="工作风格" tabindex="-1">工作风格 <a class="header-anchor" href="#工作风格" aria-label="Permalink to &quot;工作风格&quot;">​</a></h3><ul><li>办公室：伯克希尔总部仅20余人</li><li>会议：极少召开正式会议</li><li>沟通：偏好电话而非邮件</li></ul><h2 id="在股东信中的角色" tabindex="-1">在股东信中的角色 <a class="header-anchor" href="#在股东信中的角色" aria-label="Permalink to &quot;在股东信中的角色&quot;">​</a></h2><p>每封股东信的作者，1977-2024年共48封。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a> - 管理的企业</li><li><a href="./查理·芒格.html">查理·芒格</a> - 搭档</li><li><a href="./本·格雷厄姆.html">本·格雷厄姆</a> - 老师</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',34)])])}const b=a(i,[["render",d]]);export{c as __pageData,b as default};
